// Input
const keys = {};
window.addEventListener('keydown', e => {
  keys[e.code] = true;
  if (e.code === 'KeyP') useDebug = !useDebug;
});
window.addEventListener('keyup', e => keys[e.code] = false);


function resolvePlayerCollisions() {
  // Move and resolve collisions (AABB) using collision box
  // Horizontal movement
  player.touchingWall = 0; // -1 = left wall, 1 = right wall, 0 = none
  player.x += player.vx;
  for (const plat of platforms) {
    const colBox = {
      x: player.x + player.colOffsetX,
      y: player.y + player.colOffsetY,
      width: player.colWidth,
      height: player.colHeight
    };
    if (
      colBox.x < plat.x + plat.width &&
      colBox.x + colBox.width > plat.x &&
      colBox.y < plat.y + plat.height &&
      colBox.y + colBox.height > plat.y
    ) {
      if (player.vx > 0) {
        player.x = plat.x - player.colOffsetX - player.colWidth;
        player.touchingWall = 1;
      } else if (player.vx < 0) {
        player.x = plat.x + plat.width - player.colOffsetX;
        player.touchingWall = -1;
      }
      player.vx = 0;
    }
  }

  // Vertical movement
  player.y += player.vy;
  player.grounded = false;
  for (const plat of platforms) {
    const colBox = {
      x: player.x + player.colOffsetX,
      y: player.y + player.colOffsetY,
      width: player.colWidth,
      height: player.colHeight
    };
    if (
      colBox.x < plat.x + plat.width &&
      colBox.x + colBox.width > plat.x &&
      colBox.y < plat.y + plat.height &&
      colBox.y + colBox.height > plat.y
    ) {
      if (player.vy > 0) {
        player.y = plat.y - player.colOffsetY - player.colHeight;
        player.vy = 0;
        player.grounded = true;
        player.canDoubleJump = false;
      } else if (player.vy < 0) {
        player.y = plat.y + plat.height - player.colOffsetY;
        player.vy = 0;
      }
    }
  }
}

function updatePlayerMovement() {
  // Update facing direction
  if (player.vx > 0) player.facing = 'right';
  else if (player.vx < 0) player.facing = 'left';
  // When wall-pressing, face toward the wall
  if (!player.grounded && player.touchingWall !== 0 && player.vy > 0) {
    player.facing = player.touchingWall === 1 ? 'right' : 'left';
  }
  let moving = player.vx !== 0;
  let prevSprite = player.currentSprite;

  // Interrupt flip if the player lands or starts wall-pressing
  const wallSliding = !player.grounded && player.touchingWall !== 0 && player.vy > 0;
  if (player.isFlipping && (player.grounded || wallSliding)) {
    player.isFlipping = false;
  }

  if (player.isFlipping) {
    // Advance the flip animation; stop when the last frame finishes
    flipSprite.update(1000 / 60);
    if (flipSprite.frame === flipSprite.frameCount - 1) {
      // Last frame just became active — let it show for one tick, then end
      player.isFlipping = false;
    }
    player.currentSprite = flipSprite;
  } else if (wallSliding) {
    // Player is wall-sliding
    player.currentSprite = wallPressSprite;
  } else if (!player.grounded) {
    if (player.vy < 0) {
      // Player is jumping up
      player.currentSprite = jumpingSprite;
    } else {
      // Player is falling down
      player.currentSprite = fallingSprite;
    }
  } else if (moving) {
    player.currentSprite = runningSprite;
  } else {
    player.currentSprite = idleSprite;
  }
  // Reset animation if sprite changed (but not while flipping — it was just reset on trigger)
  if (player.currentSprite !== prevSprite && !player.isFlipping) {
    player.currentSprite.reset();
  }
  // Only animate if moving, in the air, or idle (flip is handled above already)
  if (!player.isFlipping && (moving || !player.grounded || player.currentSprite === idleSprite)) {
    player.currentSprite.update(1000 / 60);
  }
  // Horizontal movement (player input)
  player.vx = 0;
  // Left
  if (keys['ArrowLeft'] || keys['KeyA']) player.vx = -player.speed;
  // Right
  if (keys['ArrowRight'] || keys['KeyD']) player.vx = player.speed;

  // Apply decaying wall jump external force
  if (player.wallJumpForceTimer > 0) {
    const dt = 1000 / 60;
    const t = player.wallJumpForceTimer / 250; // 1 → 0 over 250ms
    player.vx += player.wallJumpForceX * t;
    player.wallJumpForceTimer = Math.max(0, player.wallJumpForceTimer - dt);
  }

  // Jump
  if (keys['Space'] && player.grounded && !player.spaceWasPressed) {
    player.vy = -player.jumpPower;
    player.grounded = false;
    player.canDoubleJump = true;
    player.spaceWasPressed = true;
  }

if (keys['Space'] && !player.grounded && player.touchingWall === 0 && !player.spaceWasPressed && useDebug) {
  player.vy = -player.jumpPower * 0.85;
  player.canDoubleJump = false;
  player.spaceWasPressed = true;
  // Trigger flip animation — play all 16 frames exactly once
  player.isFlipping = true;
  flipSprite.reset();
}

  // Wall jump: jump away from wall when pressing Space while touching a wall in the air
  if (keys['Space'] && !player.grounded && player.touchingWall !== 0 && !player.spaceWasPressed) {
    player.vy = -player.jumpPower * 0.8;
    // Set external force away from wall — ramps down to 0 over 250ms
    player.wallJumpForceX = -player.touchingWall * player.speed * 1.2;
    player.wallJumpForceTimer = 400;
    player.canDoubleJump = true; // wall jump restores double jump
    player.spaceWasPressed = true;
  }

  if (!keys['Space']) {
    player.spaceWasPressed = false;
  }

  // Variable jump height: if Space is released while moving upward, reduce vy
  if (!keys['Space'] && player.vy < 0) {
    player.vy *= 0.5;
  }

  // Slow fall when pressing against a wall in the air
  if (player.touchingWall !== 0 && !player.grounded && player.vy > 0) {
    player.vy = Math.min(player.vy, 2.5); // cap downward speed while wall-sliding
  }

  // Gravity
  player.vy += 0.5;

  resolvePlayerCollisions();
}

function checkRingCollection() {
  const colBox = {
    x: player.x + player.colOffsetX,
    y: player.y + player.colOffsetY,
    width: player.colWidth,
    height: player.colHeight
  };
  rings = rings.filter(ring => {
    // Ring sprite box
    const spriteX = ring.x - player.width / 2;
    const spriteY = ring.y + TILE_SIZE - player.height;
    const spriteW = player.width;
    const spriteH = player.height;
    // Ring pickup hitbox: 50% of sprite box, centred
    const ringHitW = spriteW * 0.5;
    const ringHitH = spriteH * 0.5;
    const ringHitX = spriteX + (spriteW - ringHitW) / 2;
    const ringHitY = spriteY + (spriteH - ringHitH) / 2;
    const overlaps =
      colBox.x < ringHitX + ringHitW &&
      colBox.x + colBox.width > ringHitX &&
      colBox.y < ringHitY + ringHitH &&
      colBox.y + colBox.height > ringHitY;
    if (overlaps) {
      // Spawn a collection animation at the ring's centre
      ringAnimations.push({
        x: ring.x,
        y: ring.y,
        elapsed: 0,
        duration: 500 // ms
      });
      collectedRings++;
      if (collectedRings === totalRings) {
        ringTimerRunning = false; // stop when all collected
      }
      return false; // Remove the ring
    }
    return true;
  });
}

function update() {
  updatePlayerMovement();
  checkRingCollection();

  // Advance ring animations
  const dt = 1000 / 60;
  ringAnimations = ringAnimations.filter(anim => {
    anim.elapsed += dt;
    return anim.elapsed < anim.duration;
  });

  // Advance ring collection timer
  if (ringTimerRunning) ringTimer += dt / 1000;

  // Smooth camera follow: lerp camera toward player center
  const targetX = player.x + player.width / 2 - canvas.width / 2;
  const targetY = player.y + player.height / 2 - canvas.height / 2;
  camera.x += (targetX - camera.x) * (1 - camera.smoothing);
  camera.y += (targetY - camera.y) * (1 - camera.smoothing);

  // Snail proximity shake — spastic, unpredictable, ramps up when closer
  const SNAIL_SHAKE_RADIUS = 2700; // world-px distance at which shake starts
  const SNAIL_SHAKE_MAX    = 32;  // max shake amplitude in pixels
  const playerCX = player.x + player.width  / 2;
  const playerCY = player.y + player.height / 2;
  let maxProximity = 0;
  for (const snail of snails) {
    const snailCX = snail.x + (snailSprite.frameWidth  * (player.width / 80)) / 2;
    const snailCY = snail.y + (snailSprite.frameHeight * (player.width / 80)) / 2;
    const dist = Math.hypot(playerCX - snailCX, playerCY - snailCY);
    const proximity = Math.max(0, 1 - dist / SNAIL_SHAKE_RADIUS);
    if (proximity > maxProximity) maxProximity = proximity;
  }
  if (maxProximity > 0) {
    camera.shakeTime += dt / 1000; // seconds
    const t = camera.shakeTime;
    // Sum several sine waves at irrational-ratio frequencies so it never repeats
    const amp = Math.pow(maxProximity, 1.5) * SNAIL_SHAKE_MAX;
    camera.shakeX = amp * (
      Math.sin(t * 47.3)  * 0.40 +
      Math.sin(t * 119.7) * 0.25 +
      Math.sin(t * 73.1)  * 0.20 +
      Math.sin(t * 211.3) * 0.15
    );
    camera.shakeY = amp * (
      Math.sin(t * 83.9)  * 0.40 +
      Math.sin(t * 137.2) * 0.25 +
      Math.sin(t * 61.5)  * 0.20 +
      Math.sin(t * 193.7) * 0.15
    );
  } else {
    camera.shakeX = 0;
    camera.shakeY = 0;
  }
}

function draw() {
  ctx.clearRect(0, 0, canvas.width, canvas.height);

  // Draw sky gradient background (screen space, unaffected by camera)
  const skyGradient = ctx.createLinearGradient(0, 0, 0, canvas.height);
  skyGradient.addColorStop(0,   '#c2e3ffff'); // deep sky blue at top
  skyGradient.addColorStop(0.6, '#d4ecffff'); // pale blue in middle
  skyGradient.addColorStop(1,   '#e4f5ffff'); // near-white at horizon
  ctx.fillStyle = skyGradient;
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  // Apply camera transform (with shake offset)
  ctx.save();
  ctx.translate(-Math.round(camera.x + camera.shakeX), -Math.round(camera.y + camera.shakeY));

  // (Platforms are drawn last so they always render on top of sprites — see below)

  // Animate flower and ring sprites
  flowerSprite.update(1000 / 60); // Assume 60fps game loop
  ringSprite.update(1000 / 60);
  snailSprite.update(1000 / 60);
  // Draw flowers (behind player)
  for (const flower of flowers) {
    if (typeof flowerImg !== 'undefined' && flowerImg.complete) {
      ctx.drawImage(
        flowerImg,
        flowerSprite.frame * flowerSprite.frameWidth, 0,
        flowerSprite.frameWidth, flowerSprite.frameHeight,
        flower.x - player.width,
        flower.y + TILE_SIZE - player.height * 2 + SINK_PX,
        player.width * 2,
        player.height * 2
      );
    }
  }

  // Draw snails (behind player)
  if (typeof snailImg !== 'undefined' && snailImg.complete) {
    for (const snail of snails) {
      // Scale snail the same way the player is scaled (player.width / playerFrameSize = 2.5×)
      const spriteScale = player.width / 80;
      const snailW = snailSprite.frameWidth * spriteScale;
      const snailH = snailSprite.frameHeight * spriteScale;
      // Anchor: map cell marks the base (bottom-centre) of the snail
      const drawX = snail.x + TILE_SIZE / 2 - snailW / 2;
      const drawY = snail.y + TILE_SIZE - snailH + SINK_PX;
      if (snail.flipped) {
        ctx.save();
        ctx.translate(drawX + snailW / 2, drawY + snailH / 2);
        ctx.scale(-1, 1);
        ctx.drawImage(
          snailImg,
          snailSprite.frame * snailSprite.frameWidth, 0,
          snailSprite.frameWidth, snailSprite.frameHeight,
          -snailW / 2, -snailH / 2, snailW, snailH
        );
        ctx.restore();
      } else {
        ctx.drawImage(
          snailImg,
          snailSprite.frame * snailSprite.frameWidth, 0,
          snailSprite.frameWidth, snailSprite.frameHeight,
          drawX, drawY, snailW, snailH
        );
      }
    }
  }

  // Draw signs (behind player)
  if (typeof signImg !== 'undefined' && signImg.complete) {
    const spriteScale = player.width / 80;
    const signW = signSprite.frameWidth * spriteScale;
    const signH = signSprite.frameHeight * spriteScale;
    for (const sign of signs) {
      // Anchor: map cell marks the base (bottom-centre) of the sign
      const drawX = sign.x + TILE_SIZE / 2 - signW / 2;
      const drawY = sign.y + TILE_SIZE - signH + SINK_PX;
      ctx.drawImage(
        signImg,
        signSprite.frame * signSprite.frameWidth, 0,
        signSprite.frameWidth, signSprite.frameHeight,
        drawX, drawY, signW, signH
      );
    }
  }

  // Draw player (in front of flowers, behind rings)
  ctx.save();
  const playerSprite = player.currentSprite;
  if (playerSprite && playerSprite.img && playerSprite.img.complete) {
    if (player.facing === 'left') {
      ctx.translate(player.x + player.width / 2, player.y + player.height / 2 + SINK_PX);
      ctx.scale(-1, 1);
      ctx.drawImage(
        playerSprite.img,
        playerSprite.frame * playerSprite.frameWidth, 0,
        playerSprite.frameWidth, playerSprite.frameHeight,
        -player.width / 2, -player.height / 2, player.width, player.height
      );
    } else {
      ctx.drawImage(
        playerSprite.img,
        playerSprite.frame * playerSprite.frameWidth, 0,
        playerSprite.frameWidth, playerSprite.frameHeight,
        player.x, player.y + SINK_PX, player.width, player.height
      );
    }
  } else {
    // fallback: draw a rectangle if image not loaded
    ctx.fillStyle = '#0af';
    ctx.fillRect(player.x, player.y, player.width, player.height);
  }
  ctx.restore();

  // Draw rings (in front of player)
  for (const ring of rings) {
    if (typeof ringImg !== 'undefined' && ringImg.complete) {
      ctx.drawImage(
        ringImg,
        ringSprite.frame * ringSprite.frameWidth, 0,
        ringSprite.frameWidth, ringSprite.frameHeight,
        ring.x - player.width / 2,
        ring.y + TILE_SIZE - player.height + SINK_PX,
        player.width,
        player.height
      );
    }
  }

  // Draw ring collection animations
  for (const anim of ringAnimations) {
    const t = anim.elapsed / anim.duration; // 0 → 1
    const scale = 1 + t * 1.5;             // grows from 1x to 2.5x
    const alpha = 1 - t;                   // fades from opaque to transparent
    const floatY = t * 60;                 // floats up 60px

    const baseW = player.width;
    const baseH = player.height;
    const drawW = baseW * scale;
    const drawH = baseH * scale;
    const drawX = anim.x - player.width / 2 - (drawW - baseW) / 2;
    const drawY = anim.y + TILE_SIZE - player.height - floatY - (drawH - baseH) / 2;

    if (typeof ringImg !== 'undefined' && ringImg.complete) {
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.drawImage(
        ringImg,
        ringSprite.frame * ringSprite.frameWidth, 0,
        ringSprite.frameWidth, ringSprite.frameHeight,
        drawX, drawY, drawW, drawH
      );
      ctx.restore();
    }
  }

  // Debug outlines
  if (useDebug) {
    ctx.save();
    ctx.lineWidth = 2;

    // Platforms (yellow)
    ctx.strokeStyle = 'yellow';
    for (const plat of platforms) {
      ctx.strokeRect(plat.x, plat.y, plat.width, plat.height);
    }

    // Flowers: sprite box (green)
    ctx.strokeStyle = 'green';
    for (const flower of flowers) {
      ctx.strokeRect(
        flower.x - player.width,
        flower.y + TILE_SIZE - player.height * 2,
        player.width * 2,
        player.height * 2
      );
    }

    // Rings: sprite box (blue) and hitbox (red)
    for (const ring of rings) {
      const spriteX = ring.x - player.width / 2;
      const spriteY = ring.y + TILE_SIZE - player.height;
      const spriteW = player.width;
      const spriteH = player.height;
      const ringHitW = spriteW * 0.5;
      const ringHitH = spriteH * 0.5;
      const ringHitX = spriteX + (spriteW - ringHitW) / 2;
      const ringHitY = spriteY + (spriteH - ringHitH) / 2;
      ctx.strokeStyle = 'blue';
      ctx.strokeRect(spriteX, spriteY, spriteW, spriteH);
      ctx.strokeStyle = 'red';
      ctx.strokeRect(ringHitX, ringHitY, ringHitW, ringHitH);
    }

    // Player: sprite box (blue) and collision box (red)
    ctx.strokeStyle = 'blue';
    ctx.strokeRect(player.x, player.y, player.width, player.height);
    ctx.strokeStyle = 'red';
    ctx.strokeRect(
      player.x + player.colOffsetX,
      player.y + player.colOffsetY,
      player.colWidth,
      player.colHeight
    );

    ctx.restore();
  }

  // Draw platforms on top of all sprites so ground occludes feet/bases
  if (tileset.complete) {
    for (const plat of platforms) {
      const { col, row } = plat;
      const hasTop    = solidTiles.has(`${col},${row - 1}`);
      const hasBottom = solidTiles.has(`${col},${row + 1}`);
      const hasLeft   = solidTiles.has(`${col - 1},${row}`);
      const hasRight  = solidTiles.has(`${col + 1},${row}`);
      const hasTL = solidTiles.has(`${col - 1},${row - 1}`);
      const hasTR = solidTiles.has(`${col + 1},${row - 1}`);
      const hasBL = solidTiles.has(`${col - 1},${row + 1}`);
      const hasBR = solidTiles.has(`${col + 1},${row + 1}`);
      let srcX, srcY;
      if (hasLeft && hasRight && hasTop && hasBottom && !hasBR) {
        srcX = 48; srcY = 0;
      } else if (hasLeft && hasRight && hasTop && hasBottom && !hasBL) {
        srcX = 64; srcY = 0;
      } else if (hasLeft && hasRight && hasTop && hasBottom && !hasTR) {
        srcX = 48; srcY = 16;
      } else if (hasLeft && hasRight && hasTop && hasBottom && !hasTL) {
        srcX = 64; srcY = 16;
      } else {
        const tileCol = hasLeft  ? (hasRight  ? 1 : 2) : 0;
        const tileRow = hasTop   ? (hasBottom ? 1 : 2) : 0;
        srcX = tileCol * TILESET_TILE;
        srcY = tileRow * TILESET_TILE;
      }
      ctx.drawImage(tileset, srcX, srcY, TILESET_TILE, TILESET_TILE, plat.x, plat.y, TILE_SIZE, TILE_SIZE);
    }
  } else {
    ctx.fillStyle = '#444';
    for (const plat of platforms) {
      ctx.fillRect(plat.x, plat.y, plat.width, plat.height);
    }
  }

  // End camera transform
  ctx.restore();

  // Draw ring counter HUD (top-left, screen space)
  {
    const fontSize = 14;
    const lineHeight = fontSize + 6;
    const pad = 10;
    const margin = 16;
    const allDone = collectedRings === totalRings;
    const ringLabel  = `RINGS: ${String(collectedRings).padStart(2, '0')} / ${String(totalRings).padStart(2, '0')}`;
    const timerLabel = `TIME:  ${ringTimer.toFixed(1)}s`;
    const lines = [ringLabel, timerLabel];
    ctx.save();
    ctx.font = `${fontSize}px 'Press Start 2P', monospace`;
    ctx.textAlign = 'left';
    ctx.textBaseline = 'top';
    const maxTextW = Math.max(...lines.map(l => ctx.measureText(l).width));
    const boxW = maxTextW + pad * 2;
    const boxH = lines.length * lineHeight - 6 + pad * 2;
    const boxX = margin;
    const boxY = margin;
    // White background with border
    ctx.fillStyle = 'white';
    ctx.fillRect(boxX, boxY, boxW, boxH);
    ctx.strokeStyle = '#333';
    ctx.lineWidth = 2;
    ctx.strokeRect(boxX, boxY, boxW, boxH);
    // Text — green when all rings collected
    ctx.fillStyle = allDone ? '#1a7a1a' : '#222';
    lines.forEach((line, i) => {
      ctx.fillText(line, boxX + pad, boxY + pad + i * lineHeight);
    });
    ctx.restore();
  }

  // Draw sign tooltips in screen space (on top of everything)
  {
    const spriteScale = player.width / 80;
    const signW = signSprite.frameWidth * spriteScale;
    const signH = signSprite.frameHeight * spriteScale;
    const playerColBox = {
      x: player.x + player.colOffsetX,
      y: player.y + player.colOffsetY,
      width: player.colWidth,
      height: player.colHeight
    };
    signs.forEach((sign, i) => {
      const lines = signTexts[i] ?? [];
      if (!lines.length) return;
      // Sign hitbox in world space
      const signLeft   = sign.x + TILE_SIZE / 2 - signW / 2;
      const signTop    = sign.y + TILE_SIZE - signH;
      const signRight  = signLeft + signW;
      const signBottom = signTop  + signH;
      const hovering =
        playerColBox.x < signRight &&
        playerColBox.x + playerColBox.width > signLeft &&
        playerColBox.y < signBottom &&
        playerColBox.y + playerColBox.height > signTop;
      if (!hovering) return;

      // Convert sign centre to screen space (include shake so tooltip stays on sign)
      const screenX = signLeft + signW / 2 - Math.round(camera.x + camera.shakeX);
      const screenY = signTop            - Math.round(camera.y + camera.shakeY);

      const fontSize = 14;
      const lineHeight = fontSize + 6;
      ctx.save();
      ctx.font = `${fontSize}px 'Press Start 2P', monospace`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'top';

      const pad = 10;
      const maxTextW = Math.max(...lines.map(l => ctx.measureText(l).width));
      const boxW = maxTextW + pad * 2;
      const boxH = lines.length * lineHeight - 6 + pad * 2; // -6 removes extra gap after last line
      const boxX = screenX - boxW / 2;
      const boxY = screenY - boxH - 8; // 8px gap above sign

      // White background with border
      ctx.fillStyle = 'white';
      ctx.fillRect(boxX, boxY, boxW, boxH);
      ctx.strokeStyle = '#333';
      ctx.lineWidth = 2;
      ctx.strokeRect(boxX, boxY, boxW, boxH);

      // Draw each line
      ctx.fillStyle = '#222';
      lines.forEach((line, li) => {
        ctx.fillText(line, screenX, boxY + pad + li * lineHeight);
      });
      ctx.restore();
    });
  }
}

function loop() {
  update();
  draw();
  requestAnimationFrame(loop);
}

ringTimerRunning = true;
loop();
